var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"다, 당장 이 손 놓으란 말이에요......!","JPN":"こ、この手を離してください……！","ENG":"L-let go of me!","TWN":"我、我叫你們立刻放手……！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"콜록콜록......!","JPN":"ゲホゲホ……","ENG":"*Cough cough*","TWN":"咳咳！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"슬슬 엘릭서 효능도 떨어져 가는 것 같은데 얌전히 산소마스크나 쓰라고.","JPN":"そろそろエリクサーの効果も落ちてきたようだし、大人しく酸素マスクを付けたら？","ENG":"Be a good girl and put on the oxygen mask, will you? The Elixir's effects are running out.","TWN":"聖水的效果也漸漸減弱了，妳就乖乖地用氧氣面罩吧。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"안 그러면 내일쯤엔 머리가 꽤 아플걸?","JPN":"そうしないと明日、頭痛で苦労するよ？","ENG":"Otherwise you'll have a splitting headache tomorrow.","TWN":"不然明天頭會很痛喔？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"어, 어째서 선택 받은 존재인 내가 이런 비루한 인간에게......","JPN":"ど、どうして選ばれた存在である私が、卑しい人間なんかに……","ENG":"I-I am the blessed one! How could you weak humans lay your hands on me?","TWN":"為、為什麼我這個被選中的存在，會被這種卑劣的人類……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아 그리고 당신은 변호사를 선임할 수 있고, 변명을 마음대로 할 수 있습니다. ","JPN":"あと、あなたは弁護士を選任できますし、好きなだけ言い訳ができます。","ENG":"You have a right to hire an attorney and make all the excuses you want.","TWN":"妳可以請律師，也可以隨意為自己申辯。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"크윽, 난 정의의 집행자라고요! 아무도 날 심판할 수 없는 것이에요! ","JPN":"くうっ、私は正義の執行者なんです！\\n誰も私を審判することなどできないのです！","ENG":"Gah, I'm the bringer of justice! Exterminator of bullies! You police cannot judge me!","TWN":"呃，我是正義執行者！沒有人可以審判我的！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"헛소리 더 하면 공무집행방해로 가중처벌을 받을 수도 있어요.","JPN":"それ以上うわ言を言い続けるなら、\\n公務執行妨害で加重処罰されることもあります。","ENG":"Keep on blabbering, and you'll be charged with aggravated obstruction of justice.","TWN":"妳再說胡說八道，我們就要以妨礙公務罪加重妳的處罰了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"얌전히 부모님께 설명할 준비나 하는 게 좋을걸?","JPN":"大人しく、お母さんとお父さんに何て言い訳するか考えたほうがいいと思うよ？","ENG":"If I were you, I'd be thinking about what I would tell my parents about this.","TWN":"妳還是好好想想該怎麼和家長解釋吧？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"......딸꾹.","JPN":"……ひくっ。","ENG":"Hic...","TWN":"……咿。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"부, 부모님을 불러오는 건 반칙인 것이에요......","JPN":"りょ、両親を呼び出すなんて卑怯なのです……","ENG":"Y-you can't call my parents... That's unfair...","TWN":"叫、叫家長是犯規吧……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRLSTUDENT_EXTRA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"자, 그럼 뒤는 맡길게요.","JPN":"じゃあ、あとはお願いしますね。","ENG":"Now, I'll leave the rest to you.","TWN":"好了，那之後就交給你們了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"정말 수고 많았소, 경위. 덕분에 별 피해 없이 사건이 마무리 됐군.","JPN":"本当にご苦労だった、マエカワ警部補。\\nおかげで大きな被害もなく事件が解決したな。","ENG":"Excellent work, Lieutenant. This ended with no additional casualties, all thanks to you.","TWN":"真是辛苦妳了，警衛。幸虧有妳，我們才能沒有人員傷亡，順利結束這次事件。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"카운터 범죄 전담반이라는 소리를 처음 들었을 때는 질 나쁜 농담이라고 생각했는데......","JPN":"最初にカウンター犯罪専任班と聞いた時には、\\n質の悪い冗談だと思ったんだが……","ENG":"I have to admit, I thought a Counter crimes squad was a bad joke,","TWN":"一開始聽到制裁者犯罪專案組的時候，我還以為是什麼惡劣玩笑……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"경위를 보니 내 생각이 잘못된 것 같군.","JPN":"警部補を見たら、どうやら私の考えが間違っていたようだ。","ENG":"but I was all wrong, seeing how you handle things.","TWN":"但是看到警衛，我才發現自己想錯了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"과연 대 카운터 전문가라 불릴 만 한 것 같네.","JPN":"さすが、対カウンター専門家だと呼ばれるだけある。","ENG":"You're an anti-Counter specialist, and there's no doubt about it.","TWN":"警衛果然稱得上是對付制裁者的專家呢。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 전문가라뇨. 적당한 속임수를 써서 햇병아리들이나 상대하는 정도가 한계인 걸요.","JPN":"はは、専門家だなんて。\\n子供騙しの手口でちょろいカウンターを相手にするぐらいが限界です。","ENG":"You're just being nice. What I can do is use silly tricks to make petty, naive criminals look foolish. That's as far as I'll go.","TWN":"哈哈，什麼專家啊。只是適當地用了些騙術，頂多騙騙這些菜鳥罷了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"괜히 거물들 사이에 고개를 들이밀었다가 목이 날아간 사람도 꽤 많아요.","JPN":"下手に大物の事件に関わって、首が飛んだ人もかなりいるんですよ。","ENG":"I know what happens when someone tries to play out of their league; heads roll.","TWN":"也有很多人去招惹那些大人物，結果腦袋就直接搬家了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"하하, 험한 일을 하다 보면 승진에서 밀릴 수도 있는 법이지 않겠나.","JPN":"はは、危ない仕事をやっていたら昇進を逃すこともよくあるからな。","ENG":"Hah hah, we're in a rough business. People get fired and demoted all the time, don't they?","TWN":"哈哈，只要做危險的工作，確實有可能在升遷路上被排擠呢。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아, 제 말은 물리적으로 날아갔다는 뜻인데요......","JPN":"あ、私が言ったのは物理的に飛んだという意味ですが……","ENG":"No, I mean literally. Literally the heads rolled across the ground.","TWN":"啊，我指的是物理上的腦袋搬家……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"저, 정말이오?","JPN":"ほ、本当か？","ENG":"A-are you serious?","TWN":"真、真的嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그야 당연히 소문이긴 한데요...... 저 같은 말단에게 인사 파일을 보여 주지는 않으니까요.","JPN":"まあ、あくまで噂ですが……\\n私のような下っ端に人事ファイルを閲覧させてはくれませんからね。","ENG":"Well, it's just a rumor, of course... They'd never show me the actual files on that, not at my pay grade.","TWN":"那當然是謠言啦……畢竟那種檔案才不會給我這種基層人員看呢。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"혹시 저희 부서로 전근 신청하실 생각 없으세요?","JPN":"私の部署に移られる予定はありませんか？","ENG":"Say, could I interest you in transferring to my division?","TWN":"你有沒有想過要調到我們的部門呢？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"안 그래도 사람이 부족해서 신청만 하면 바로 승인 날 것 같은데.","JPN":"ただでさえ人手不足なので、申請さえすれば承認は間違いないと思いますが。","ENG":"We're really short on hands. I'm sure I could get approval right away.","TWN":"我們正好人手不足，只要申請應該很快就會通過的。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"같이 어둠 속에 묻힌 진실을 파헤쳐 보는 거죠!","JPN":"一緒に闇に埋もれた真実を暴きましょう！","ENG":"We can unearth truth buried in the shadows together!","TWN":"讓我們一起揭開埋在黑暗中的真相吧！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"크흠 크흠!","JPN":"ゴホン、ゴホン！","ENG":"*Clears throat*","TWN":"咳咳！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"아쉽지만 그 제안은 사양해야겠소.","JPN":"残念ながら、その提案は遠慮しておこう。","ENG":"I'm afraid I'll have to humbly decline the offer.","TWN":"很遺憾，但請容我拒絕這個提案。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"이쪽도 늘 현장업무에 이리저리 치이는 입장이라서 말이지......","JPN":"こちらも、いつも現場の業務に振り回される立場でね……","ENG":"We have work to be done on our end as well.","TWN":"畢竟我這裡也在第一線忙得不可開交……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"그럼 살펴가시오.","JPN":"では、気をつけて。","ENG":"Take care, now.","TWN":"那就保重了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXTRA_POLICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 오늘도 스카우트 실패네......","JPN":"はは、今日もスカウト失敗か……","ENG":"Heh, zero applicants, as usual.","TWN":"哈哈，今天的挖角也失敗了呢……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"대체 인력 충원은 언제쯤 되는 거람?","JPN":"いったい人員補充はいつしてくれるの？","ENG":"Are they ever going to consider sending people here?","TWN":"到底什麼時候才能補充人員啊？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};